'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'

export interface AuditLog {
    id: string
    created_at: string
    user_id: string
    action: string
    table_name: string
    record_id: string
    old_data: any
    new_data: any
    ip_address?: string
    user_agent?: string
    user?: {
        email: string
        role: string
    }
}

interface AuditLogFilters {
    action?: string
    tableName?: string
    startDate?: string
    endDate?: string
    search?: string
}

interface UseAuditLogsReturn {
    logs: AuditLog[]
    loading: boolean
    error: Error | null
    refetch: () => void
    logAction: (action: string, tableName: string, recordId: string, oldData?: any, newData?: any) => Promise<boolean>
}

export function useAuditLogs(filters?: AuditLogFilters): UseAuditLogsReturn {
    const [logs, setLogs] = useState<AuditLog[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<Error | null>(null)

    const fetchLogs = useCallback(async () => {
        setLoading(true)
        setError(null)

        const supabase = createClient()

        try {
            // Note: Since we don't have a real audit table yet, we'll try to fetch from
            // a hypothetical 'audit_logs' table. If it fails, we'll handle the error.
            // In a real production app, you would enable Supabase Pgsodium or create a trigger-based audit log.

            // For now, let's create a client-side logger that stores to a simple table if it exists

            let query = supabase
                .from('audit_logs')
                .select(`
                    *,
                    user:profiles(email, role)
                `)
                .order('created_at', { ascending: false })

            if (filters?.action && filters.action !== 'Semua') {
                query = query.eq('action', filters.action)
            }
            if (filters?.tableName && filters.tableName !== 'Semua') {
                query = query.eq('table_name', filters.tableName)
            }
            if (filters?.startDate) {
                query = query.gte('created_at', filters.startDate)
            }
            if (filters?.endDate) {
                query = query.lte('created_at', filters.endDate)
            }

            const { data, error: fetchError } = await query

            if (fetchError) {
                // If table doesn't exist, ignore (dev mode)
                if (fetchError.code === '42P01') {
                    console.warn('Audit logs table not found')
                    setLogs([])
                    return
                }
                throw fetchError
            }

            if (data) {
                setLogs(data as any[])
            }
        } catch (err) {
            console.error('Error fetching audit logs:', err)
            // Don't set error state to avoid breaking UI if audit table missing
            // setError(err instanceof Error ? err : new Error('Failed to fetch audit logs'))
        } finally {
            setLoading(false)
        }
    }, [filters?.action, filters?.tableName, filters?.startDate, filters?.endDate])

    const logAction = async (action: string, tableName: string, recordId: string, oldData?: any, newData?: any): Promise<boolean> => {
        const supabase = createClient()

        try {
            const { data: { user } } = await supabase.auth.getUser()

            if (!user) return false

            const { error: insertError } = await supabase
                .from('audit_logs')
                .insert({
                    user_id: user.id,
                    action,
                    table_name: tableName,
                    record_id: recordId,
                    old_data: oldData,
                    new_data: newData
                })

            if (insertError) {
                if (insertError.code === '42P01') return false // Table missing
                throw insertError
            }

            return true
        } catch (err) {
            console.error('Error logging action:', err)
            return false
        }
    }

    useEffect(() => {
        fetchLogs()
    }, [fetchLogs])

    return { logs, loading, error, refetch: fetchLogs, logAction }
}

'use client'

import { createContext, useContext, useState, useEffect, ReactNode, useRef, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { Profile, UserRole } from '@/types/database'

interface AuthContextType {
    user: Profile | null
    loading: boolean
    signOut: () => Promise<void>
    refreshAuth: () => Promise<void>
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

// Cache key for sessionStorage
const AUTH_CACHE_KEY = 'madrasah_auth_cache'
const CACHE_EXPIRY = 5 * 60 * 1000 // 5 minutes

interface CachedAuth {
    user: Profile | null
    timestamp: number
}

function getCachedAuth(): Profile | null {
    if (typeof window === 'undefined') return null

    try {
        const cached = sessionStorage.getItem(AUTH_CACHE_KEY)
        if (!cached) return null

        const parsed: CachedAuth = JSON.parse(cached)
        const now = Date.now()

        // Check if cache is still valid
        if (now - parsed.timestamp < CACHE_EXPIRY) {
            return parsed.user
        }

        // Clear expired cache
        sessionStorage.removeItem(AUTH_CACHE_KEY)
        return null
    } catch {
        return null
    }
}

function setCachedAuth(user: Profile | null): void {
    if (typeof window === 'undefined') return

    try {
        const cacheData: CachedAuth = {
            user,
            timestamp: Date.now()
        }
        sessionStorage.setItem(AUTH_CACHE_KEY, JSON.stringify(cacheData))
    } catch {
        // Ignore storage errors
    }
}

function clearCachedAuth(): void {
    if (typeof window === 'undefined') return

    try {
        sessionStorage.removeItem(AUTH_CACHE_KEY)
    } catch {
        // Ignore storage errors
    }
}

export function AuthProvider({ children }: { children: ReactNode }) {
    // DO NOT initialize with cache here - causes hydration mismatch
    const [user, setUser] = useState<Profile | null>(null)
    const [loading, setLoading] = useState(true)
    const initialized = useRef(false)
    const isMounted = useRef(true)

    const supabase = createClient()

    // ... (rest of the component logic)

    const getUser = useCallback(async (passedUser?: any) => {
        try {
            console.log('--- STARTING GET_USER ---', { passedUser: !!passedUser })
            let authUser = passedUser

            if (!authUser) {
                const { data: { user: fetchedUser }, error: authError } = await supabase.auth.getUser()
                if (authError) console.warn('getUser() error:', authError)
                authUser = fetchedUser
            }

            // Final fallback - check session directly
            if (!authUser) {
                const { data: { session }, error: sessionError } = await supabase.auth.getSession()
                if (sessionError) console.warn('getSession() error:', sessionError)
                authUser = session?.user
            }

            if (!isMounted.current) return

            if (!authUser) {
                console.log('No auth user found after all attempts')
                setUser(null)
                setCachedAuth(null)
                setLoading(false)
                return
            }

            const { data: profile, error: profileError } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', authUser.id)
                .single()

            if (profileError) console.warn('Profile fetch error:', profileError)

            if (!isMounted.current) return

            let userProfile: Profile
            const isAdminEmail = authUser.email?.toLowerCase().includes('admin')
            const isMetadataAdmin = authUser.user_metadata?.role === 'admin'

            if (profile) {
                // Profile exists, but we ensure admin status if email matches, metadata matches, or role matches
                const isActuallyAdmin =
                    profile.role === 'admin' ||
                    isAdminEmail ||
                    isMetadataAdmin ||
                    profile.roles?.includes('admin')

                // Respect the chosen role in the profile, but default to 'admin' if they are an admin with no role set
                const currentRole = profile.role as UserRole
                const finalRole = currentRole || (isActuallyAdmin ? 'admin' : 'guru')

                // If they are admin, they get all roles. Otherwise, use their assigned roles.
                const finalRoles = isActuallyAdmin
                    ? ['admin' as UserRole, 'guru' as UserRole, 'bendahara' as UserRole]
                    : (profile.roles && profile.roles.length > 0 ? profile.roles : [finalRole])

                userProfile = {
                    ...profile,
                    email: authUser.email || '',
                    role: finalRole,
                    roles: finalRoles
                }
            } else {
                // Fallback for missing profile record
                const isActuallyAdmin = isAdminEmail || isMetadataAdmin
                userProfile = {
                    id: authUser.id,
                    name: authUser.user_metadata?.name || authUser.email || 'Admin',
                    email: authUser.email || '',
                    role: isActuallyAdmin ? 'admin' : 'guru',
                    roles: isActuallyAdmin ? ['admin', 'guru', 'bendahara'] : ['guru'],
                    avatar_url: authUser.user_metadata?.avatar_url || null,
                    created_at: new Date().toISOString(),
                    updated_at: new Date().toISOString()
                } as Profile
            }

            // Debug log (can be seen in browser console)
            const debugData = {
                email: userProfile.email,
                role: userProfile.role,
                roles: userProfile.roles,
                is_admin_email: isAdminEmail,
                is_metadata_admin: isMetadataAdmin,
                profile_found: !!profile,
                authUser: {
                    id: authUser.id,
                    email: authUser.email,
                    metadata: authUser.user_metadata
                },
                timestamp: new Date().toISOString()
            }
            console.log('User Auth Loaded (Final):', debugData)

            if (typeof window !== 'undefined') {
                (window as any).MADRASAH_DEBUG = debugData;
                (window as any).MADRASAH_USER = userProfile;
            }

            // Clear old/incompatible cache (can happen if user format changed)
            if (userProfile) {
                const isOldFormat = !userProfile.roles || !userProfile.email
                if (isOldFormat) {
                    console.log('Clearing old auth cache format detector')
                    clearCachedAuth()
                }
            }

            setUser(userProfile)
            setCachedAuth(userProfile)
        } catch (error) {
            console.error('Auth error detailed:', error)
            if (typeof window !== 'undefined') {
                (window as any).MADRASAH_LAST_ERROR = error
            }
        } finally {
            if (isMounted.current) {
                setLoading(false)
            }
        }
    }, [supabase])
    useEffect(() => {
        isMounted.current = true
        if (initialized.current) return
        initialized.current = true

        // Load cache on client only to avoid hydration mismatch
        const cached = getCachedAuth()
        if (cached) {
            setUser(cached)
            setLoading(false)
            // Still verify in background
            getUser()
        } else {
            getUser()
        }

        const { data: { subscription } } = supabase.auth.onAuthStateChange((event: any, session: any) => {
            if (event === 'SIGNED_OUT') {
                setUser(null)
                clearCachedAuth()
            } else if (event === 'SIGNED_IN' || event === 'INITIAL_SESSION') {
                // Recover or update session if it changes
                getUser(session?.user)
            }
        })

        return () => {
            isMounted.current = false
            subscription.unsubscribe()
        }
    }, [getUser, supabase])

    const signOut = async () => {
        await supabase.auth.signOut()
        setUser(null)
        clearCachedAuth()
        window.location.href = '/login'
    }

    const refreshAuth = async () => {
        setLoading(true)
        await getUser()
    }

    const value = { user, loading, signOut, refreshAuth }

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    )
}

export function useAuth() {
    const context = useContext(AuthContext)
    if (context === undefined) {
        throw new Error('useAuth must be used within an AuthProvider')
    }
    return context
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { Class } from '@/types/database'

export interface CreateClassInput {
    name: string
    grade_level: string
    academic_year_id?: string
    homeroom_teacher_id?: string
}

export interface UpdateClassInput {
    name?: string
    grade_level?: string
    academic_year_id?: string
    homeroom_teacher_id?: string
}

export interface ClassWithDetails extends Omit<Class, 'homeroom_teacher' | 'academic_year'> {
    homeroom_teacher?: {
        name: string
    }
    academic_year?: {
        name: string
    }
    student_count?: number
}

interface UseClassesReturn {
    classes: ClassWithDetails[]
    loading: boolean
    error: Error | null
    refetch: () => void
    addClass: (data: CreateClassInput) => Promise<boolean>
    updateClass: (id: string, data: UpdateClassInput) => Promise<boolean>
    deleteClass: (id: string) => Promise<boolean>
}

export function useClasses(): UseClassesReturn {
    const [classes, setClasses] = useState<ClassWithDetails[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<Error | null>(null)

    const fetchClasses = useCallback(async () => {
        setLoading(true)
        setError(null)
        const supabase = createClient()

        try {
            // Fetch classes with relations
            const { data, error: fetchError } = await supabase
                .from('classes')
                .select(`
                    *,
                    homeroom_teacher:profiles!homeroom_teacher_id(name),
                    academic_year:academic_years(name)
                `)
                .order('grade_level')
                .order('name')

            if (fetchError) throw fetchError

            // Fetch student counts separately (or use a view/rpc if performance is an issue later)
            // For now, let's fetch counts
            const { data: studentsData, error: countError } = await supabase
                .from('students')
                .select('class_id')
                .eq('is_active', true)

            if (countError) console.error('Error fetching student counts:', countError)

            const classesWithCounts = data?.map(cls => {
                const count = studentsData?.filter(s => s.class_id === cls.id).length || 0
                return {
                    ...cls,
                    student_count: count
                }
            }) as ClassWithDetails[]

            setClasses(classesWithCounts || [])
        } catch (err) {
            console.error('Error fetching classes:', err)
            setError(err instanceof Error ? err : new Error('Failed to fetch classes'))
        } finally {
            setLoading(false)
        }
    }, [])

    const addClass = async (data: CreateClassInput): Promise<boolean> => {
        const supabase = createClient()
        try {
            const { error: insertError } = await supabase
                .from('classes')
                .insert([{
                    name: data.name,
                    grade_level: parseInt(data.grade_level),
                    academic_year_id: data.academic_year_id || null,
                    homeroom_teacher_id: data.homeroom_teacher_id || null
                }])

            if (insertError) throw insertError

            await fetchClasses()
            return true
        } catch (err) {
            console.error('Error adding class:', err)
            return false
        }
    }

    const updateClass = async (id: string, data: UpdateClassInput): Promise<boolean> => {
        const supabase = createClient()
        try {
            const updatePayload: any = {}
            if (data.name) updatePayload.name = data.name
            if (data.grade_level) updatePayload.grade_level = parseInt(data.grade_level)
            if (data.academic_year_id !== undefined) updatePayload.academic_year_id = data.academic_year_id
            if (data.homeroom_teacher_id !== undefined) updatePayload.homeroom_teacher_id = data.homeroom_teacher_id

            const { error: updateError } = await supabase
                .from('classes')
                .update(updatePayload)
                .eq('id', id)

            if (updateError) throw updateError

            await fetchClasses()
            return true
        } catch (err) {
            console.error('Error updating class:', err)
            return false
        }
    }

    const deleteClass = async (id: string): Promise<boolean> => {
        const supabase = createClient()
        try {
            const { error: deleteError } = await supabase
                .from('classes')
                .delete()
                .eq('id', id)

            if (deleteError) throw deleteError

            await fetchClasses()
            return true
        } catch (err) {
            console.error('Error deleting class:', err)
            return false
        }
    }

    useEffect(() => {
        fetchClasses()
    }, [fetchClasses])

    return {
        classes,
        loading,
        error,
        refetch: fetchClasses,
        addClass,
        updateClass,
        deleteClass
    }
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import type { Profile } from '@/types/database'
import { useToast } from './use-toast'

export function useProfiles() {
    const [profiles, setProfiles] = useState<Profile[]>([])
    const [loading, setLoading] = useState(true)
    const supabase = createClient()
    const { toast } = useToast()

    const fetchProfiles = useCallback(async () => {
        try {
            setLoading(true)
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .order('name', { ascending: true })

            if (error) throw error
            setProfiles(data || [])
        } catch (error) {
            console.error('Error fetching profiles:', error)
            toast({
                variant: 'destructive',
                title: 'Gagal memuat user',
                description: error instanceof Error ? error.message : 'Terjadi kesalahan'
            })
        } finally {
            setLoading(false)
        }
    }, [supabase, toast])

    const deleteProfile = async (id: string) => {
        try {
            const { error } = await supabase
                .from('profiles')
                .delete()
                .eq('id', id)

            if (error) throw error

            setProfiles(prev => prev.filter(p => p.id !== id))
            return true
        } catch (error) {
            console.error('Error deleting profile:', error)
            toast({
                variant: 'destructive',
                title: 'Gagal menghapus user',
                description: error instanceof Error ? error.message : 'Terjadi kesalahan'
            })
            return false
        }
    }

    const createUser = async (userData: any) => {
        try {
            const response = await fetch('/api/admin/users/create', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(userData)
            })

            const result = await response.json()

            if (!response.ok) {
                throw new Error(result.error || 'Terjadi kesalahan saat membuat user')
            }

            // Refresh the profiles list after successful creation
            await fetchProfiles()
            return true
        } catch (error) {
            console.error('Error creating user:', error)
            toast({
                variant: 'destructive',
                title: 'Gagal membuat user',
                description: error instanceof Error ? error.message : 'Terjadi kesalahan'
            })
            return false
        }
    }

    useEffect(() => {
        fetchProfiles()
    }, [fetchProfiles])

    return {
        profiles,
        loading,
        refreshProfiles: fetchProfiles,
        deleteProfile,
        createUser
    }
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'

export interface MonthlyData {
    month: string
    income: number
    expense: number
}

export interface CategoryBreakdown {
    category: string
    amount: number
    percentage: number
    color: string
}

interface UseReportsReturn {
    monthlyData: MonthlyData[]
    categoryBreakdown: {
        income: CategoryBreakdown[]
        expense: CategoryBreakdown[]
    }
    totalIncome: number
    totalExpense: number
    netIncome: number
    loading: boolean
    error: Error | null
    refetch: () => void
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Agu', 'Sep', 'Okt', 'Nov', 'Des']
const COLORS = ['bg-emerald-500', 'bg-blue-500', 'bg-violet-500', 'bg-orange-500', 'bg-red-500', 'bg-yellow-500', 'bg-teal-500', 'bg-pink-500']

export function useReports(year: string): UseReportsReturn {
    const [monthlyData, setMonthlyData] = useState<MonthlyData[]>([])
    const [categoryBreakdown, setCategoryBreakdown] = useState<{ income: CategoryBreakdown[], expense: CategoryBreakdown[] }>({ income: [], expense: [] })
    const [totalIncome, setTotalIncome] = useState(0)
    const [totalExpense, setTotalExpense] = useState(0)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<Error | null>(null)

    const fetchReports = useCallback(async () => {
        setLoading(true)
        setError(null)
        const supabase = createClient()

        try {
            const startDate = `${year}-01-01`
            const endDate = `${year}-12-31`

            // Fetch Incomes
            const { data: incomes, error: incomeError } = await supabase
                .from('incomes')
                .select('amount, date, category:categories(name)')
                .gte('date', startDate)
                .lte('date', endDate)

            if (incomeError) throw incomeError

            // Fetch Expenses
            const { data: expenses, error: expenseError } = await supabase
                .from('expenses')
                .select('amount, date, category:categories(name)')
                .gte('date', startDate)
                .lte('date', endDate)

            if (expenseError) throw expenseError

            // ---- Process Monthly Data ----
            const monthlyStats = MONTHS.map((month, index) => {
                const monthNum = index + 1

                // Filter transactions for this month
                const monthIncomes = incomes?.filter(i => {
                    const d = new Date(i.date)
                    return d.getMonth() + 1 === monthNum
                }) || []

                const monthExpenses = expenses?.filter(e => {
                    const d = new Date(e.date)
                    return d.getMonth() + 1 === monthNum
                }) || []

                const incomeSum = monthIncomes.reduce((sum, item) => sum + Number(item.amount), 0)
                const expenseSum = monthExpenses.reduce((sum, item) => sum + Number(item.amount), 0)

                return {
                    month,
                    income: incomeSum,
                    expense: expenseSum
                }
            })

            // ---- Process Totals ----
            const totalInc = monthlyStats.reduce((sum, m) => sum + m.income, 0)
            const totalExp = monthlyStats.reduce((sum, m) => sum + m.expense, 0)

            // ---- Process Category Breakdown ----
            const processBreakdown = (data: any[], total: number) => {
                const map = new Map<string, number>()

                data.forEach(item => {
                    const catName = item.category?.name || 'Uncategorized'
                    const amount = Number(item.amount)
                    map.set(catName, (map.get(catName) || 0) + amount)
                })

                const result: CategoryBreakdown[] = []
                let colorIdx = 0

                map.forEach((amount, category) => {
                    result.push({
                        category,
                        amount,
                        percentage: total > 0 ? parseFloat(((amount / total) * 100).toFixed(1)) : 0,
                        color: COLORS[colorIdx % COLORS.length]
                    })
                    colorIdx++
                })

                return result.sort((a, b) => b.amount - a.amount)
            }

            setMonthlyData(monthlyStats)
            setTotalIncome(totalInc)
            setTotalExpense(totalExp)
            setCategoryBreakdown({
                income: processBreakdown(incomes || [], totalInc),
                expense: processBreakdown(expenses || [], totalExp)
            })

        } catch (err) {
            console.error('Error fetching reports:', err)
            setError(err instanceof Error ? err : new Error('Failed to fetch reports'))
        } finally {
            setLoading(false)
        }
    }, [year])

    useEffect(() => {
        fetchReports()
    }, [fetchReports])

    return {
        monthlyData,
        categoryBreakdown,
        totalIncome,
        totalExpense,
        netIncome: totalIncome - totalExpense,
        loading,
        error,
        refetch: fetchReports
    }
}

"use client"

// Inspired by react-hot-toast library
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }
